import React, { useEffect, useRef } from 'react';
import { graphql, PageProps } from 'gatsby';
import { MDXProvider } from '@mdx-js/react';

import { PostStyleComp } from '../../components/common/Post';
import { Introduce } from '../../components/common/Introduce';
import { ToCStyleComp } from '../../components/common/Post/ToCStyleComp';
import { PostTemplate } from '../../templates/PostTemplate';

const MarkdownRemark = ({ data }: PageProps<Queries.PostDetailQuery>) => {
  const html = data.markdownRemark?.html as string;
  const toc = data.markdownRemark?.tableOfContents as string;
  const commentEl = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = commentEl.current as HTMLDivElement;
    const element = document.createElement('script');
    element.async = true;
    element.src = 'https://utteranc.es/client.js';
    element.setAttribute('repo', 'galaxy4276/galaxy4276.github.io');
    element.setAttribute('issue-term', 'pathname');
    element.setAttribute('theme', 'github-light');
    element.setAttribute('crossorigin', 'anonymous');
    root.append(element);
  }, []);

  return (
    <PostTemplate>
      <MDXProvider
          components={{
            blockquote: props => (
              <span
                className="pl-3 border-l-2 border-sky-500 w-full"
                {...props}
              />
            ),
            strong: props => (
              <b {...props} />
            ),
          }}
        >
        <PostStyleComp>
          <div className="pb-3 flex flex-col">
            <h1>{data.markdownRemark?.frontmatter?.title}</h1>
            <p className="text-slate-500">
              {data.markdownRemark?.frontmatter?.date}
            </p>
            <hr/>
          </div>
        </PostStyleComp>
        <ToCStyleComp>
          <section className="
            w-full bg-slate-500 text-white p-3 drop-shadow-md rounded-md
          ">
            <h2 className="text-2xl font-semibold text-slate-50">TOC</h2>
            <div
              dangerouslySetInnerHTML={{ __html: toc }}
            />
          </section>
        </ToCStyleComp>
        <PostStyleComp>
          <div dangerouslySetInnerHTML={{ __html: html }} />
        </PostStyleComp>
      </MDXProvider>

      <hr className="py-3 mt-6" />
      <Introduce />
      <hr />
      <div ref={commentEl}></div>
    </PostTemplate>
  )
};

export default MarkdownRemark;

export const query = graphql`
  query PostDetail($id: String) {
    markdownRemark(id: { eq: $id }) {
      html
      tableOfContents
      frontmatter {
        title
        date(formatString: "YYYY년 MM월 DD일") 
        slug
        tag
      }
    }
  }
`;
